import{_ as t,o as e,c as l,a4 as a}from"./chunks/framework.Bz0lZ1uX.js";const y=JSON.parse('{"title":"议论文人物素材库","description":"","frontmatter":{},"headers":[],"relativePath":"materials/index.md","filePath":"materials/index.md","lastUpdated":null}'),r={name:"materials/index.md"},d=a('<h1 id="议论文人物素材库" tabindex="-1">议论文人物素材库 <a class="header-anchor" href="#议论文人物素材库" aria-label="Permalink to &quot;议论文人物素材库&quot;">​</a></h1><p>欢迎来到议论文人物素材库！这里汇集了高质量的议论文人物写作素材，助你写出精彩议论文。</p><h2 id="人物素材一览" tabindex="-1">人物素材一览 <a class="header-anchor" href="#人物素材一览" aria-label="Permalink to &quot;人物素材一览&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">人物</th><th style="text-align:left;">核心定位</th><th style="text-align:left;">适用主题</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/materials/人物素材/中村修二.html">中村修二</a></td><td style="text-align:left;">蓝色LED之父</td><td style="text-align:left;">坚持、创新、专注</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/威廉·勒梅修里尔.html">威廉·勒梅修里尔</a></td><td style="text-align:left;">工程师良知的守护者</td><td style="text-align:left;">责任、诚信、勇气</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/弗雷德里克·图多·戈里.html">弗雷德里克·图多·戈里</a></td><td style="text-align:left;">人工制冷时代的开创者</td><td style="text-align:left;">创新、打破垄断</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/梁文峰.html">梁文峰</a></td><td style="text-align:left;">DeepSeek创始人</td><td style="text-align:left;">远见、科技自立、家国情怀</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/Paper2Gal开发者.html">Paper2Gal开发者</a></td><td style="text-align:left;">大学生跨界创新典范</td><td style="text-align:left;">创新、跨界融合、青年担当</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/泰奥·杨森.html">泰奥·杨森</a></td><td style="text-align:left;">风力仿生兽的造物主</td><td style="text-align:left;">坚持、匠心、人与自然</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/马丁·路德·金.html">马丁·路德·金</a></td><td style="text-align:left;">非暴力抗争的民权领袖</td><td style="text-align:left;">平等、正义、信念、梦想</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/马科长.html">马科长</a></td><td style="text-align:left;">基层干部的责任担当</td><td style="text-align:left;">责任、抉择智慧、平衡之道</td></tr></tbody></table><hr><h2 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h2><ol><li><strong>按人物浏览</strong> - 点击左侧侧边栏的人物名称直达素材页</li><li><strong>搜索功能</strong> - 使用顶部搜索框按关键词快速定位</li><li><strong>按主题筛选</strong> - 根据作文主题选择对应的人物素材</li></ol><hr><h2 id="素材特点" tabindex="-1">素材特点 <a class="header-anchor" href="#素材特点" aria-label="Permalink to &quot;素材特点&quot;">​</a></h2><ul><li><strong>可直接抄写的论证片段</strong> - 每个素材提供2个角度的论证段落</li><li><strong>标签化分类</strong> - 便于按主题快速检索</li><li><strong>写作建议</strong> - 包含段落位置、过渡句式、扣题方法等实用指导</li></ul>',10),i=[d];function s(n,o,h,f,g,x){return e(),l("div",null,i)}const c=t(r,[["render",s]]);export{y as __pageData,c as default};
